head.script:
scwin.initData = {
	"chart" : {
		"chartUnit" : 10,
		"chartIntervalCount" : 5,
		"sliderIntervalTime" : 5000,
		"elyrsErnLabel" : {
			"Lgwtpw" : "대수력",
			"Smlhp" : "소수력",
			"Snpw" : "태양광",
			"Wdpw" : "풍력",
			"Tdpw" : "조력",
			"Wtht" : "수열"
		},
		"etcErnLabel" : {
			"Cer" : "CER",
			"Rec" : "REC",
			"Dr" : "DR",
			"Ovsea" : "해외(매출)"
		},
		"cnstnExcclcLabel" : {
			"Fltplt" : "정수장",
			"Itkpl" : "취수장",
			"Prnplc" : "가압장",
			"Etc" : "기타소비"
		},
		"dashChartEvent" : false
	},
	"dashBasin" : {
		"dashBasin1" : "영섬유역",
		"dashBasin2" : "낙동강유역",
		"dashBasin3" : "한강유역",
		"dashBasin4" : "금강유역",
		"dashBasin5" : "전체",
		"dashBasin6" : "영섬유역",
		"dashBasin7" : "낙동강유역",
		"dashBasin8" : "한강유역",
		"dashBasin9" : "금강유역"
	},
	"dashBasinValue" : {
		"전체" : "ALL",
		"한강유역" : "H",
		"금강유역" : "G",
		"영섬유역" : "Y",
		"낙동강유역" : "N"
	},
	"dashBasinCode" : {
		"ALL" : "ALL",
		"H" : "01",
		"G" : "02",
		"Y" : "03",
		"N" : "04"
	},
	"observeEvent" : false,
	"minYear" : 1978,
	"maxYear" : Number(utilLib.getCurrentDate("yyyy")) + 4,
	"dashLeftEvent" : false
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSEC3000000", {"initScreenCallback" : scwin.initDatas});
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.initDatas = function() {
	var params = $p.getParameter("param");
	var basinIdx = 0;
	if (params && params.basin && params.basin != "ALL") {
		var basinIdx = Object.keys(scwin.initData.dashBasinValue).slice(-4).reverse().findIndex(item => scwin.initData.dashBasinValue[item] == params.basin) - 1;
		if (basinIdx <= 0) {
			basinIdx--;
		}
	}

	scwin.setDashYear();
	scwin.setDashBasin(basinIdx, true);
	scwin.setDashLeftEvent();

	scwin.chartSlide(grpChartElyrsErn, scwin.initData.chart.elyrsErnLabel);
	scwin.chartSlide(grpChartEtcErn, scwin.initData.chart.etcErnLabel);
	scwin.chartSlide(grpChartCnstnExcclc, scwin.initData.chart.cnstnExcclcLabel);

	// 데이터 조회
	scwin.searchDatas();
	// 서브박스 클릭에 따른 차트 변경 이벤트_0920
	scwin.squareBoxClickEvent();

	// ecsLib.setChartResizeObserver(this);
};

/**
 * 화면 닫힘시에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.onpageunload = function() {
	/*
	// 자동 슬라이드 기능 없애달래서 주석처리함_0920
	clearInterval(scwin.initData.grpChartElyrsErn.loopInterval);
	clearInterval(scwin.initData.grpChartEtcErn.loopInterval);
	clearInterval(scwin.initData.grpChartCnstnExcclc.loopInterval);
	*/
};

/**
 * 데이터들을 조회한다.
 */
scwin.searchDatas = async function() {
	[...document.querySelectorAll("#" + $p.getFrameId() + " .dash-con-box-cl .dash-box .slider-pagination li:nth-child(2)")].forEach(emt => emt.click());
	var fetchArr = [
		// 발전 수익, 우측 물방울 라벨(연간발전수익) 데이터, 발전 수익 차트(5개년), 발전 수익 점유율 차트 조회
		scwin.searchElyrsErnData().then(scwin.searchElyrsErnDataCallBack),
		// 기타 수익, 우측 물방울 라벨(연간기타수익) 데이터, 기타 수익 차트(5개년) 생성, 기타 수익 점유율 차트 조회
		scwin.searchEtcErnData().then(scwin.searchEtcErnDataCallBack),
		// 소비 정산, 우측 물방울 라벨(연간소비정산) 데이터, 소비 정산 차트(5개년), 소비 정산 점유율 차트 조회
		scwin.searchCnstnExcclcData().then(scwin.searchCnstnExcclcDataCallBack),
	];
	await Promise.all(fetchArr);

	scwin.setWaterDropTotalErnData();
};

//============================================================================================
// 좌측 라벨(날짜, 유역 선택)
//============================================================================================
/**
 * 좌측 날짜 데이터 바인딩
 * @param {
 	num : 계산이나 셋팅할 숫자
 	type : ["clac", "year"]에 따라 현재 데이터에서 계산할지 직접 셋팅할지 설정
 }
 */
scwin.setDashYear = function(num, type) {
	type = type || "calc";
	var dashYear = dmaDashYear.getJSON();
	var setYearFunc = function(year) {
		var no = 1;
		var count = Object.keys(dashYear).length - 1;
		for (var idx = (Number(year) - Math.floor(count / 2)); idx <= (Number(year) + Math.floor(count / 2)); idx++) {
			dashYear["dashYear" + no++] = Number(idx);
		}
		dashYear.dashYearSelected = Number(year);
	};
	if (!Object.values(dashYear).filter(obj => obj).length) {
		var nowYear = utilLib.getCurrentDate("yyyy");
		setYearFunc(nowYear);
	}

	if (num) {
		if (type == "calc") {
			var isChange = false;
			var dashYearSelectedTemp = dashYear.dashYearSelected;
			dashYear.dashYearSelected = "";
			if (num < 0 && Object.values(dashYear).find(value => value && scwin.initData.minYear >= value)) {
				isChange = true;
			} else if (num > 0 && Object.values(dashYear).find(value => value && value >= scwin.initData.maxYear)) {
				isChange = true;
			}
			if (!isChange) {
				for (var key of Object.keys(dashYear)) {
					if (!key.includes("Selected")) {
						dashYear[key] = dashYear[key] + Number(num);
					}
				}
			}
			dashYear.dashYearSelected = dashYearSelectedTemp;
		} else if (type == "year") {
			setYearFunc(num);
		}
	}
	dmaDashYear.setJSON(dashYear);

	var selectedEmt = [...document.querySelectorAll("#" + $p.getFrameId() + " .dash-con-box-cl ul[id$='grpDashBeltYear'].dash-belt-text-group li")].find(emt => emt.textContent == dmaDashYear.get("dashYearSelected"));
	document.querySelectorAll("#" + $p.getFrameId() + " .dash-con-box-cl ul[id$='grpDashBeltYear'].dash-belt-text-group li.dash-belt-text-color").forEach(emt => {
		//emt.classList.remove("dash-belt-text-box");
		emt.classList.remove("dash-belt-text-color");
	});
	if (selectedEmt) {
		//selectedEmt.classList.add("dash-belt-text-box");
		selectedEmt.classList.add("dash-belt-text-color");
	}
	var liEmt = [...document.querySelectorAll("#" + $p.getFrameId() + " .dash-con-box-cl ul[id$='grpDashBeltYear'].dash-belt-text-group li")];
	liEmt.forEach(emt => {
		emt.removeAttribute("style");
	});
	liEmt = liEmt.filter(emt => scwin.initData.minYear + 1 >= Number(emt.textContent) || Number(emt.textContent) >= scwin.initData.maxYear - 3);
	liEmt.forEach(emt => {
		emt.style.cursor = "not-allowed";
	});
};

/**
 * 좌측 유역 데이터 바인딩
 * @param {
 	num : 계산할 숫자,
 	type : selected 
 }
 */
scwin.setDashBasin = function(num, type) {
	var dashBasin = dmaDashBasin.getJSON();
	if (!Object.values(dashBasin).filter(obj => obj).length) {
		for (var idx in Object.keys(dashBasin)) {
			dashBasin["dashBasin" + (Number(idx) + 1)] = scwin.initData.dashBasin["dashBasin" + (Number(idx) + 1)];
		}
		dashBasin.dashBasinSelected = dashBasin["dashBasin" + Math.floor(Object.keys(dashBasin).length / 2)];
		dmaDashBasin.setJSON(dashBasin);
	}

	var tempBasin = dmaDashBasin.getJSON();
	if (num < 0) {
		if (num == -1) { // 아래 1칸
			if (type) {
				dashBasin.dashBasinSelected = tempBasin.dashBasin6;
			}
			dashBasin.dashBasin1 = tempBasin.dashBasin2;
			dashBasin.dashBasin2 = tempBasin.dashBasin3;
			dashBasin.dashBasin3 = tempBasin.dashBasin4;
			dashBasin.dashBasin4 = tempBasin.dashBasin5;
			dashBasin.dashBasin5 = tempBasin.dashBasin6;
			dashBasin.dashBasin6 = tempBasin.dashBasin7;
			dashBasin.dashBasin7 = tempBasin.dashBasin8;
			dashBasin.dashBasin8 = tempBasin.dashBasin9;
			dashBasin.dashBasin9 = tempBasin.dashBasin5;
		} else if (num == -2) { // 아래 2칸
			if (type) {
				dashBasin.dashBasinSelected = tempBasin.dashBasin7;
			}
			dashBasin.dashBasin1 = tempBasin.dashBasin3;
			dashBasin.dashBasin2 = tempBasin.dashBasin4;
			dashBasin.dashBasin3 = tempBasin.dashBasin5;
			dashBasin.dashBasin4 = tempBasin.dashBasin6;
			dashBasin.dashBasin5 = tempBasin.dashBasin7;
			dashBasin.dashBasin6 = tempBasin.dashBasin8;
			dashBasin.dashBasin7 = tempBasin.dashBasin9;
			dashBasin.dashBasin8 = tempBasin.dashBasin5;
			dashBasin.dashBasin9 = tempBasin.dashBasin1;
		}
	} else if (num > 0) {
		if (num == 1) { // 위 1칸
			if (type) {
				dashBasin.dashBasinSelected = tempBasin.dashBasin4;
			}
			dashBasin.dashBasin1 = tempBasin.dashBasin5;
			dashBasin.dashBasin2 = tempBasin.dashBasin1;
			dashBasin.dashBasin3 = tempBasin.dashBasin2;
			dashBasin.dashBasin4 = tempBasin.dashBasin3;
			dashBasin.dashBasin5 = tempBasin.dashBasin4;
			dashBasin.dashBasin6 = tempBasin.dashBasin5;
			dashBasin.dashBasin7 = tempBasin.dashBasin6;
			dashBasin.dashBasin8 = tempBasin.dashBasin7;
			dashBasin.dashBasin9 = tempBasin.dashBasin3;
		} else if (num == 2) { // 위 2칸
			if (type) {
				dashBasin.dashBasinSelected = tempBasin.dashBasin3;
			}
			dashBasin.dashBasin1 = tempBasin.dashBasin9;
			dashBasin.dashBasin2 = tempBasin.dashBasin5;
			dashBasin.dashBasin3 = tempBasin.dashBasin1;
			dashBasin.dashBasin4 = tempBasin.dashBasin2;
			dashBasin.dashBasin5 = tempBasin.dashBasin3;
			dashBasin.dashBasin6 = tempBasin.dashBasin4;
			dashBasin.dashBasin7 = tempBasin.dashBasin5;
			dashBasin.dashBasin8 = tempBasin.dashBasin6;
			dashBasin.dashBasin9 = tempBasin.dashBasin7;
		}
	} else if (num == 0) {
		if (dashBasin.dashBasinSelected != tempBasin.dashBasin5) {
			dashBasin.dashBasinSelected = tempBasin.dashBasin5;
		}
	}
	dmaDashBasin.setJSON(dashBasin);

	var selectedEmt = [...document.querySelectorAll("#" + $p.getFrameId() + " .dash-con-box-cl ul[id$='grpDashBeltBasin'].dash-belt-text-group li")].filter(emt => emt.textContent == dmaDashBasin.get("dashBasinSelected"));
	document.querySelectorAll("#" + $p.getFrameId() + " .dash-con-box-cl ul[id$='grpDashBeltBasin'].dash-belt-text-group li.dash-belt-text-color").forEach(emt => {
		//emt.classList.remove("dash-belt-text-box");
		emt.classList.remove("dash-belt-text-color");
	});
	if (selectedEmt) {
		//selectedEmt.classList.add("dash-belt-text-box");
		for (emt of selectedEmt) {
			emt.classList.add("dash-belt-text-color");
		} 
	}
};

/**
 * 좌측 메뉴 스크롤 이벤트
 */
scwin.setDashLeftEvent = function() {
	// 날짜
	var beltYearEmt = document.getElementById(grpDashBeltYear.getID());
	setTimeout(() => {
		var liYearEmt = document.getElementById(spnDashYear5.getID()).parentElement;
		var scrollTop = (beltYearEmt.scrollHeight - liYearEmt.offsetTop) / 2 - liYearEmt.clientHeight;
		beltYearEmt.scrollTo(0, scrollTop);
	}, 300);
	beltYearEmt.addEventListener("mousewheel", function(e) {
		if (!scwin.initData.dashLeftEvent) {
			scwin.initData.dashLeftEvent = true;
			var ulEmt = e.target;
			if (e.deltaY > 0) {
				scwin.setDashYear(1);
			} else {
				scwin.setDashYear(-1);
			}
			setTimeout(() => {
				scwin.initData.dashLeftEvent = false;
			}, 10);
		}
	});
	beltYearEmt.querySelectorAll("li").forEach(emt => {
		emt.addEventListener("click", function(e) {
			var selectedYear = Number(e.target.textContent);
			if (scwin.initData.minYear + 1 < selectedYear && selectedYear < scwin.initData.maxYear - 3) {
				if (!scwin.initData.dashLeftEvent) {
					var liEmt = e.target;
					var ulId = e.target;
					if (ulId.tagName.toLowerCase() == "span") {
						ulId = "#" + ulId.parentElement.parentElement.id;
						liEmt = liEmt.parentElement;
					} else if (ulId.tagName.toLowerCase() == "li") {
						ulId = "#" + ulId.parentElement.id;
					} else {
						ulId = "#" + ulId.id;
					}

					var animateFunc = function() {
						$(this).css("margin-top", "");
						var direct = Number(this.getAttribute("data-direct"));
						scwin.setDashYear(selectedYear, "year");
						scwin.searchDatas();
						setTimeout(() => {
							scwin.initData.dashLeftEvent = false;
						}, 100);
					};
					var animateRemoveStyleFunc = function() {
						$(this).removeAttr("style");
					};

					scwin.initData.dashLeftEvent = true;

					var dir = 5 - Number(liEmt.children[0].id.slice(-1));
					var ulEmt = document.querySelector(ulId);
					var count = ulEmt.childElementCount;
					var liIndex = [...ulEmt.childNodes].indexOf(liEmt);
					var fontSize1 = window.innerWidth > 1730 ? "1.3rem" : "1.1rem";
					var fontSize2 = window.innerWidth > 1730 ? "1.15rem" : "1rem";
					var fontSize3 = window.innerWidth > 1730 ? "0.95rem" : "0.85rem";

					if (!liIndex) {
						setTimeout(() => {
							scwin.initData.dashLeftEvent = false;
						}, 100);
					} else if (Math.floor(count / 2) > liIndex) {
						// 위로(위클릭)
						ulEmt.setAttribute("data-direct", dir);
						if (dir == 1) {
							$(ulId + ">li:nth-child(2)").animate({
								"opacity" : "0.85",
								"transition" : "all 0.7s ease-in"
							}, 700, animateRemoveStyleFunc);
							$(ulId + ">li:nth-child(3)").animate({
								"font-size" : fontSize2,
								"opacity" : "0.9"
							}, 700, animateRemoveStyleFunc);
							$(ulId + ">li:nth-child(4)").animate({
								"font-size" : fontSize1,
								//"color" : "#288BE4",
								"opacity" : "1"
							}, 700, animateRemoveStyleFunc);
							$(ulId + ">li:nth-child(5)").animate({
								"font-size" : fontSize2,
								//"color" : "#BFBFBF",
								"opacity" : "0.9"
							}, 700, animateRemoveStyleFunc);
							$(ulId + ">li:nth-child(6)").animate({
								"font-size" : fontSize3,
								"opacity" : "0.85"
							}, 700, animateRemoveStyleFunc);
							$(ulId + ">li:nth-child(7)").animate({
								"opacity" : "0",
								"transition" : "all 0.4s ease"
							}, 400, animateRemoveStyleFunc);
							var marginTop = window.innerWidth > 1730 ? "-75%" : "17%";
							$(ulId).animate({
								"marginTop" : marginTop
							}, 700, animateFunc);
						} else if (dir == 2) {
							$(ulId + ">li:first-child").animate({
								"font-size" : fontSize3,
								"opacity" : "0.85"
							}, 700, animateRemoveStyleFunc);
							$(ulId + ">li:nth-child(2)").animate({
								"font-size" : fontSize2,
								"opacity" : "0.9"
							}, 700, animateRemoveStyleFunc);
							$(ulId + ">li:nth-child(3)").animate({
								"font-size" : fontSize1,
								//"color" : "#288BE4",
								"opacity" : "1"
							}, 700, animateRemoveStyleFunc);
							$(ulId + ">li:nth-child(4)").animate({
								"font-size" : fontSize2,
								"opacity" : "0.9"
							}, 700, animateRemoveStyleFunc);
							$(ulId + ">li:nth-child(5)").animate({
								"font-size" : fontSize3,
								//"color" : "#BFBFBF",
								"opacity" : "0.85"
							}, 700, animateRemoveStyleFunc);
							$(ulId + ">li:nth-child(6)").animate({
								"opacity" : "0",
								"transition" : "all 0.4s ease"
							}, 700, animateRemoveStyleFunc);
							var marginTop = window.innerWidth > 1730 ? "-10%" : "82%";
							$(ulId).animate({
								"marginTop" : marginTop
							}, 700, animateFunc);
						}
					} else if (Math.floor(count / 2) < liIndex) {
						// 아래로(아래클릭)
						ulEmt.setAttribute("data-direct", dir);
						var ulEmt = document.querySelector(ulId);
						if (dir == -1) {
							$(ulId + ">li:nth-child(3)").animate({
								"opacity" : "0",
								"transition" : "all 0.4s ease"
							}, 400, animateRemoveStyleFunc);
							$(ulId + ">li:nth-child(4)").animate({
								"font-size" : fontSize3,
								"opacity" : "0.85"
							}, 700, animateRemoveStyleFunc);
							$(ulId + ">li:nth-child(5)").animate({
								"font-size" : fontSize2,
								//"color" : "#BFBFBF",
								"opacity" : "0.9"
							}, 700, animateRemoveStyleFunc);
							$(ulId + ">li:nth-child(6)").animate({
								"font-size" : fontSize1,
								//"color" : "#288BE4",
								"opacity" : "1"
							}, 700, animateRemoveStyleFunc);
							$(ulId + ">li:nth-child(7)").animate({
								"font-size" : fontSize2,
								"opacity" : "0.9"
							}, 700, animateRemoveStyleFunc);
							$(ulId + ">li:nth-child(8)").animate({
								"opacity" : "0.85",
								"transition" : "all 0.7s ease-in"
							}, 700, animateRemoveStyleFunc);
							var marginTop = window.innerWidth > 1730 ? "-205%" : "-195%";
							$(ulId).animate({
								"marginTop" : marginTop
							}, 700, animateFunc);
						} else if (dir == -2) {
							$(ulId + ">li:nth-child(4)").animate({
								"opacity" : "0",
								"transition" : "all 0.4s ease"
							}, 700, animateRemoveStyleFunc);
							$(ulId + ">li:nth-child(5)").animate({
								"font-size" : fontSize3,
								//"color" : "#BFBFBF",
								"opacity" : "0.85"
							}, 700, animateRemoveStyleFunc);
							$(ulId + ">li:nth-child(6)").animate({
								"font-size" : fontSize2,
								//"color" : "#BFBFBF",
								"opacity" : "0.9"
							}, 700, animateRemoveStyleFunc);
							$(ulId + ">li:nth-child(7)").animate({
								"font-size" : fontSize1,
								//"color" : "#288BE4",
								"opacity" : "1"
							}, 700, animateRemoveStyleFunc);
							$(ulId + ">li:nth-child(8)").animate({
								"font-size" : fontSize2,
								//"color" : "#BFBFBF",
								"opacity" : "0.9"
							}, 700, animateRemoveStyleFunc);
							var marginTop = window.innerWidth > 1730 ? "-270%" : "-265%";
							$(ulId).animate({
								"marginTop" : marginTop
							}, 700, animateFunc);
						}
					} else {
						setTimeout(() => {
							scwin.setDashYear(selectedYear, "year");
							scwin.searchDatas();
							scwin.initData.dashLeftEvent = false;
						}, 100);
					}
				}
			}
		});
	});

	// 유역
	var beltBasinEmt = document.getElementById(grpDashBeltBasin.getID());
	setTimeout(() => {
		var liBasinEmt = document.getElementById(spnDashBasin9.getID()).parentElement;
		var scrollTop = (beltBasinEmt.scrollHeight - liBasinEmt.offsetTop) / 2 - liBasinEmt.clientHeight;
		beltBasinEmt.scrollTo(0, scrollTop);
	}, 300);
	beltBasinEmt.addEventListener("mousewheel", function(e) {
		if (!scwin.initData.dashLeftEvent) {
			scwin.initData.dashLeftEvent = true;
			var ulEmt = e.target;
			if (e.deltaY > 0) {
				scwin.setDashBasin(-1);
			} else {
				scwin.setDashBasin(1);
			}
			setTimeout(() => {
				scwin.initData.dashLeftEvent = false;
			}, 10);
		}
	});
	document.querySelectorAll("#" + $p.getFrameId() + " .dash-con-box-cl .dash-belt-text-group[id$='grpDashBeltBasin'] > li").forEach(emt => {
		emt.addEventListener("click", function(e) {
			if (!scwin.initData.dashLeftEvent) {
				var liEmt = e.target;
				var ulId = e.target;
				if (ulId.tagName.toLowerCase() == "span") {
					ulId = "#" + ulId.parentElement.parentElement.id;
					liEmt = liEmt.parentElement;
				} else if (ulId.tagName.toLowerCase() == "li") {
					ulId = "#" + ulId.parentElement.id;
				} else {
					ulId = "#" + ulId.id;
				}

				var animateFunc = function() {
					$(this).css("margin-top", "");
					/*
					var childId = "#" + $(this).attr("id") + ">li:last-child";
					$(childId).removeAttr("style");
					var childEmt = $(childId).detach().prependTo(this);
					childEmt.detach().appendTo(this);
					*/
					var direct = Number(this.getAttribute("data-direct"));
					scwin.setDashBasin(direct, true);
					scwin.searchDatas();
					setTimeout(() => {
						scwin.initData.dashLeftEvent = false;
					}, 100);
				};
				var animateRemoveStyleFunc = function() {
					$(this).removeAttr("style");
				};

				scwin.initData.dashLeftEvent = true;

				var dir = 5 - Number(liEmt.children[0].id.slice(-1));
				var ulEmt = document.querySelector(ulId);
				var count = ulEmt.childElementCount;
				var liIndex = [...ulEmt.childNodes].indexOf(liEmt);
				var fontSize1 = window.innerWidth > 1730 ? "1.3rem" : "1.1rem";
				var fontSize2 = window.innerWidth > 1730 ? "1.15rem" : "1rem";
				var fontSize3 = window.innerWidth > 1730 ? "0.95rem" : "0.85rem";

				if (!liIndex) {
					setTimeout(() => {
						scwin.initData.dashLeftEvent = false;
					}, 100);
				} else if (Math.floor(count / 2) > liIndex) {
					// 위로(위클릭)
					ulEmt.setAttribute("data-direct", dir);
					if (dir == 1) {
						$(ulId + ">li:nth-child(2)").animate({
							"opacity" : "0.85",
							"transition" : "all 0.7s ease-in"
						}, 700, animateRemoveStyleFunc);
						$(ulId + ">li:nth-child(3)").animate({
							"font-size" : fontSize2,
							"opacity" : "0.9"
						}, 700, animateRemoveStyleFunc);
						$(ulId + ">li:nth-child(4)").animate({
							"font-size" : fontSize1,
							//"color" : "#288BE4",
							"opacity" : "1"
						}, 700, animateRemoveStyleFunc);
						$(ulId + ">li:nth-child(5)").animate({
							"font-size" : fontSize2,
							//"color" : "#BFBFBF",
							"opacity" : "0.9"
						}, 700, animateRemoveStyleFunc);
						$(ulId + ">li:nth-child(6)").animate({
							"font-size" : fontSize3,
							"opacity" : "0.85"
						}, 700, animateRemoveStyleFunc);
						$(ulId + ">li:nth-child(7)").animate({
							"opacity" : "0",
							"transition" : "all 0.4s ease"
						}, 400, animateRemoveStyleFunc);
						var marginTop = window.innerWidth > 1730 ? "-75%" : "17%";
						$(ulId).animate({
							"marginTop" : marginTop
						}, 700, animateFunc);
					} else if (dir == 2) {
						$(ulId + ">li:first-child").animate({
							"font-size" : fontSize3,
							"opacity" : "0.85"
						}, 700, animateRemoveStyleFunc);
						$(ulId + ">li:nth-child(2)").animate({
							"font-size" : fontSize2,
							"opacity" : "0.9"
						}, 700, animateRemoveStyleFunc);
						$(ulId + ">li:nth-child(3)").animate({
							"font-size" : fontSize1,
							//"color" : "#288BE4",
							"opacity" : "1"
						}, 700, animateRemoveStyleFunc);
						$(ulId + ">li:nth-child(4)").animate({
							"font-size" : fontSize2,
							"opacity" : "0.9"
						}, 700, animateRemoveStyleFunc);
						$(ulId + ">li:nth-child(5)").animate({
							"font-size" : fontSize3,
							//"color" : "#BFBFBF",
							"opacity" : "0.85"
						}, 700, animateRemoveStyleFunc);
						$(ulId + ">li:nth-child(6)").animate({
							"opacity" : "0",
							"transition" : "all 0.4s ease"
						}, 700, animateRemoveStyleFunc);
						var marginTop = window.innerWidth > 1730 ? "-10%" : "82%";
						$(ulId).animate({
							"marginTop" : marginTop
						}, 700, animateFunc);
					}
				} else if (Math.floor(count / 2) < liIndex) {
					// 아래로(아래클릭)
					ulEmt.setAttribute("data-direct", dir);
					var ulEmt = document.querySelector(ulId);
					if (dir == -1) {
						$(ulId + ">li:nth-child(3)").animate({
							"opacity" : "0",
							"transition" : "all 0.4s ease"
						}, 400, animateRemoveStyleFunc);
						$(ulId + ">li:nth-child(4)").animate({
							"font-size" : fontSize3,
							"opacity" : "0.85"
						}, 700, animateRemoveStyleFunc);
						$(ulId + ">li:nth-child(5)").animate({
							"font-size" : fontSize2,
							//"color" : "#BFBFBF",
							"opacity" : "0.9"
						}, 700, animateRemoveStyleFunc);
						$(ulId + ">li:nth-child(6)").animate({
							"font-size" : fontSize1,
							//"color" : "#288BE4",
							"opacity" : "1"
						}, 700, animateRemoveStyleFunc);
						$(ulId + ">li:nth-child(7)").animate({
							"font-size" : fontSize2,
							"opacity" : "0.9"
						}, 700, animateRemoveStyleFunc);
						$(ulId + ">li:nth-child(8)").animate({
							"opacity" : "0.85",
							"transition" : "all 0.7s ease-in"
						}, 700, animateRemoveStyleFunc);
						var marginTop = window.innerWidth > 1730 ? "-205%" : "-195%";
						$(ulId).animate({
							"marginTop" : marginTop
						}, 700, animateFunc);
					} else if (dir == -2) {
						$(ulId + ">li:nth-child(4)").animate({
							"opacity" : "0",
							"transition" : "all 0.4s ease"
						}, 700, animateRemoveStyleFunc);
						$(ulId + ">li:nth-child(5)").animate({
							"font-size" : fontSize3,
							//"color" : "#BFBFBF",
							"opacity" : "0.85"
						}, 700, animateRemoveStyleFunc);
						$(ulId + ">li:nth-child(6)").animate({
							"font-size" : fontSize2,
							//"color" : "#BFBFBF",
							"opacity" : "0.9"
						}, 700, animateRemoveStyleFunc);
						$(ulId + ">li:nth-child(7)").animate({
							"font-size" : fontSize1,
							//"color" : "#288BE4",
							"opacity" : "1"
						}, 700, animateRemoveStyleFunc);
						$(ulId + ">li:nth-child(8)").animate({
							"font-size" : fontSize2,
							//"color" : "#BFBFBF",
							"opacity" : "0.9"
						}, 700, animateRemoveStyleFunc);
						var marginTop = window.innerWidth > 1730 ? "-270%" : "-265%";
						$(ulId).animate({
							"marginTop" : marginTop
						}, 700, animateFunc);
					}
				} else {
					setTimeout(() => {
						scwin.setDashBasin(dir, true);
						scwin.searchDatas();
						scwin.initData.dashLeftEvent = false;
					}, 100);
				}
			}
		});
	});
};

