/**
 * 발전 수익 데이터를 조회한다.
 */
scwin.searchElyrsErnData = function() {
	return new Promise((resolve, rejext) => {
		var dashYear = dmaDashYear.getJSON();
		var strtDt = Number(dashYear.dashYearSelected) - 4;
		var endDt = dashYear.dashYearSelected;
		var dashBasin = dmaDashBasin.getJSON();
		var basin = dashBasin.dashBasinSelected;
		basin = scwin.initData.dashBasinCode[scwin.initData.dashBasinValue[basin]] || "ALL";

		var queryString = `?strtDt=${strtDt}`;
		queryString += `&endDt=${endDt}`;
		queryString += `&ecsBasinDivCd=${basin}`;

		var option = {
			action : "ec/cl/retrieve-prdctn-excclc.do" +
				queryString,
			method : "get",
			resData : dltElyrsErnData,
			success : function() {
				resolve();
			},
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	});
};

/**
 * 발전 수익 데이터 조회 콜백
 */
scwin.searchElyrsErnDataCallBack = function() {
	var elyrsErnData = dltElyrsErnData.getAllJSON();
	var dashYear = dmaDashYear.getJSON();
	var strtDt = Number(dashYear.dashYearSelected) - 4;
	var endDt = Number(dashYear.dashYearSelected);

	Object.keys(scwin.initData.chart.elyrsErnLabel).forEach(source => {
		var comp = $p.getComponentById("spnElyrsErn" + source);
		var data = elyrsErnData.reduce((sum, obj) => (Number(obj.inqireDe) == endDt) && obj.iemDivId.endsWith(source.toLowerCase()) ? sum + Number(obj.inqireIemVu) : sum, 0) || 0;
		comp.setLabel(ecsLib.dsplFrmt(data, 2));
	});

	// 우측 물방울 라벨(연간발전수익) 데이터 설정
	scwin.setWaterDropElyrsErnData();
	// 발전 수익 차트(5개년) 생성
	scwin.createChartElyrsErn();
	// 발전 수익 점유율 차트 생성
	scwin.createChartElyrsErnPossesn();
};

