//============================================================================================
// 차트
//============================================================================================
/**
 * 차트 시리즈 색상 핸들러
 * @param {
 	seriesID : ID,
 	index : 인덱스,
 	data : 데이터 맵,
 	values : 값
 }
 * @return 시리즈 색상
 */
scwin.fillHandler = function(seriesID, index, data, values) {
	if (index >= (scwin.initData.chartCount - 2)) {
		return "#B2CCFF"; // 6799FF
	} else {
		return ecsLib.getSkinColors().chartSolidColor2;
	}
};

/**
 * 발전 수익 차트(5개년)를 생성한다.
 */
scwin.createChartElyrsErn = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerElyrsErn";
	var chartOriginalId = grpChartElyrsErn.getOriginalID();
	Object.keys(scwin.initData.chart.elyrsErnLabel).forEach(source => {
		var compId = ""
		var comp = $p.getComponentById(chartOriginalId + source);
		if (comp) {
			compId = comp.getID();
		} else {
			compId = document.querySelector(`#${$p.getFrameId()}_${chartOriginalId}${source}`).id;
		}
		rMateChartH5.create($p.id + "chartElyrsErn" + source, compId, chartVars, "100%", "95%");
	});
};

/**
* 발전 수익 차트(5개년) 설정
 * @param id : 차트 그룹 ID
 */
scwin.chartReadyHandlerElyrsErn = function(id) {
	var chartId = "chartElyrsErn";
	var source = id.substr(Number(id.indexOf(chartId)) + chartId.length);
	var title = scwin.initData.chart.elyrsErnLabel[source];
	var dashYear = dmaDashYear.getJSON();
	var strtDt = Number(dashYear.dashYearSelected) - 4;
	var endDt = Number(dashYear.dashYearSelected);
	var elyrsErnData = dltElyrsErnData.getAllJSON();

	var chartList = [];
	for (var idx = strtDt; idx <= endDt; idx++) {
		var sumData = elyrsErnData.reduce((sum, obj) => Number(obj.inqireDe) == idx && obj.iemDivId.endsWith(source.toLowerCase()) ? sum + Number(obj.inqireIemVu) : sum, 0) || 0;

		chartList.push({
			"year" : idx,
			"elyrsErn" : sumData
		});
	}

	var maxData = chartList.reduce((max, obj) => Math.max(max, obj.elyrsErn), 0);
	var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
	var interval = Math.ceil((maxData / scwin.initData.chart.chartIntervalCount) / chartUnit) * chartUnit;

	var solidColor = ecsLib.getSkinColors().chartSolidColor1;

	//var captionSpan = "&lt;span style=&quot;color:" + solidColor + ";&quot;&gt;" + total + "ton&lt;/span&gt;";
	var layoutStr =
		'<rMateChart backgroundColor="" cornerRadius="12">'
		+ '	<Options>'
		+ '		<Caption text="' + title + ' 발전 수익" textAlign="center" paddingRight="9.6" paddingBottom="9.6" paddingLeft="9.6" fontWeight="bold" fontSize="1rem" />'
		+ '	</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true" precision="2"/>'
		+ '	<Column2DChart showDataTips="true" maxColumnWidth="11" columnWidthRatio="0.4" dataTipDisplayMode="axis">'
		+ '		<horizontalAxis>'
		+ '			<CategoryAxis id="hAxis" categoryField="year" />'
		+ '		</horizontalAxis>'
		+ '		<horizontalAxisRenderers>'
		+ '			<Axis3DRenderer axis="{hAxis}" labelGap="9" />'
		+ '		</horizontalAxisRenderers>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxis" interval="' + interval + '" />'
		+ '		</verticalAxis>'
		+ '		<series>'
		+ '			<Column2DSeries labelPosition="outside" fontWeight="bold" displayName="' + title + '" yField="elyrsErn" formatter="{numFmt}">' // fillJsFunction="' + $p.id + 'scwin.fillHandler">'
		+ '				<fill>'
		+ '					<SolidColor color="' + solidColor + '" />'
		+ '				</fill>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate />'
		+ '				</showDataEffect>'
		+ '			</Column2DSeries>'
		+ '			</series>'
		+ '	</Column2DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartList);
};

/**
 * 기타 수익 차트(5개년)를 생성한다.
