scwin.createChartCnstnExcclc = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerCnstnExcclc";
	var chartOriginalId = grpChartCnstnExcclc.getOriginalID();
	Object.keys(scwin.initData.chart.cnstnExcclcLabel).forEach(source => {
		var compId = ""
		var comp = $p.getComponentById(chartOriginalId + source);
		if (comp) {
			compId = comp.getID();
		} else {
			compId = document.querySelector(`#${$p.getFrameId()}_${chartOriginalId}${source}`).id;
