		rMateChartH5.create($p.id + "chartCnstnExcclc" + source, compId, chartVars, "100%", "95%");
	});
};

/**
* 소비 정산 차트(5개년) 설정
 * @param id : 차트 그룹 ID
 */
scwin.chartReadyHandlerCnstnExcclc = function(id) {
	var chartId = "chartCnstnExcclc";
	var source = id.substr(Number(id.indexOf(chartId)) + chartId.length);
	var title = scwin.initData.chart.cnstnExcclcLabel[source];
	var dashYear = dmaDashYear.getJSON();
	var strtDt = Number(dashYear.dashYearSelected) - 4;
	var endDt = Number(dashYear.dashYearSelected);
	var cnstnExcclcData = dltCnstnExcclcData.getAllJSON();

	var chartList = [];
	for (var idx = strtDt; idx <= endDt; idx++) {
		var sumData = cnstnExcclcData.reduce((sum, obj) => Number(obj.inqireDe) == idx && obj.iemDivId.endsWith(source.toLowerCase()) ? sum + Number(obj.inqireIemVu) : sum, 0) || 0;
		chartList.push({
			"year" : idx,
			"cnstnExcclc" : sumData
		});
	}

	var maxData = chartList.reduce((max, obj) => Math.max(max, obj.cnstnExcclc), 0);
	var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
	var interval = Math.ceil((maxData / scwin.initData.chart.chartIntervalCount) / chartUnit) * chartUnit;

	var solidColor = ecsLib.getSkinColors().chartSolidColor1;

	var layoutStr =
		'<rMateChart backgroundColor="" cornerRadius="12">'
		+ '	<Options>'
		+ '		<Caption text="' + title + ' 소비 정산" textAlign="center" paddingRight="9.6" paddingBottom="9.6" paddingLeft="9.6" fontWeight="bold" fontSize="1rem" />'
		+ '	</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true" precision="2" />'
		+ '	<Column2DChart showDataTips="true" maxColumnWidth="11" columnWidthRatio="0.4" dataTipDisplayMode="axis">'
		+ '		<horizontalAxis>'
		+ '			<CategoryAxis id="hAxis" categoryField="year" />'
		+ '		</horizontalAxis>'
		+ '		<horizontalAxisRenderers>'
		+ '			<Axis3DRenderer axis="{hAxis}" labelGap="9" />'
		+ '		</horizontalAxisRenderers>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxis" interval="' + interval + '" />'
		+ '		</verticalAxis>'
		+ '		<series>'
		+ '			<Column2DSeries labelPosition="outside" fontWeight="bold" displayName="' + title + '" yField="cnstnExcclc" formatter="{numFmt}">' // fillJsFunction="' + $p.id + 'scwin.fillHandler">'
		+ '				<fill>'
		+ '					<SolidColor color="' + solidColor + '" />'
		+ '				</fill>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate />'
		+ '				</showDataEffect>'
		+ '			</Column2DSeries>'
		+ '			</series>'
		+ '	</Column2DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartList);
};

