//============================================================================================
// 차트 슬라이드 기능
//============================================================================================
/**
 * 차트 슬라이드
 */
scwin.chartSlide = function(comp, mapping) {
	var mappingKeys = Object.keys(mapping);
	var compOrgId = comp.getOriginalID();
	scwin.initData.removeList = [];
	scwin.initData[compOrgId] = {};
	scwin.initData[compOrgId].chartWrap = document.querySelector(`#${comp.getID()}`);
	var sliderEmt = scwin.initData[compOrgId].chartWrap.querySelector(".slider");

	for (var i = 0; i < Object.keys(mapping).length; i++) {
		var compId = compOrgId + mappingKeys[i];
		var chartEmt = document.createElement("div");
		chartEmt.id = $p.getFrameId() + "_" + compId;
		chartEmt.classList.add("slider-item");
		sliderEmt.append(chartEmt);
		/*
		$p.dynamicCreate(compId, "group", {
		}, $p.getComponentById(sliderEmt.id));
		var chartComp = $p.getComponentById(compId);
		chartComp.addClass("slider-item");
		*/
	};
	scwin.initData[compOrgId].sliderWidth = sliderEmt.clientWidth;
	var sliderItems = sliderEmt.querySelectorAll(".slider-item");
	var slideCount = sliderItems.length;

	// 버튼 클릭할 때 마다 현재 슬라이드가 어디인지 알려주기 위한 변수
	scwin.initData[compOrgId].currSlide = 0;
	// 페이지네이션 생성
	var pagination = scwin.initData[compOrgId].chartWrap.querySelector(".slider-pagination");

	// 이전 차트 버튼 li
	var compId = compOrgId + "PreBtn";
	var preLiEmt = document.createElement("li");
	preLiEmt.id = $p.getFrameId() + "_" + compId;
	preLiEmt.classList.add("pagination-btn-item");
	preLiEmt.title = "이전";
	preLiEmt.innerHTML = "<<";
	pagination.append(preLiEmt);
	/*
	$p.dynamicCreate(compId, "group", {
		tagname : "li"
	}, $p.getComponentById(pagination.id));
	var liComp = $p.getComponentById(compId);
	liComp.addClass("pagination-btn-item");
	liComp.setTitle("이전");
	document.getElementById(liComp.getID()).innerHTML = "<<";
	*/

	// 차트 li
	for (var i = 0; i < slideCount; i++) {
		compId = compOrgId + mappingKeys[i] + "Li";
		var liEmt = document.createElement("li");
		liEmt.id = $p.getFrameId() + "_" + compId;
		liEmt.classList.add("pagination-item");
		liEmt.title = mapping[mappingKeys[i]];
		liEmt.innerHTML = "&#9679;";
		if (i == 0) {
			liEmt.classList.add("active");
		}
		pagination.append(liEmt);
		/*
		$p.dynamicCreate(compId, "group", {
			tagname : "li"
		}, $p.getComponentById(pagination.id));
		liComp = $p.getComponentById(compId);
		liComp.addClass("pagination-item");
		liComp.setTitle(mapping[mappingKeys[i]]);
		document.getElementById(liComp.getID()).innerHTML = "&#9679;";
		if (i == 0) {
			liComp.addClass("active");
		}
		*/
	};

	// 다음 차트 버튼 li
	compId = compOrgId + "NextBtn";
	var liNextEmt = document.createElement("li");
	liNextEmt.id = $p.getFrameId() + "_" + compId;
	liNextEmt.classList.add("pagination-btn-item");
	liNextEmt.title = "다음";
	liNextEmt.innerHTML = ">>";
	pagination.append(liNextEmt);
	/*
	$p.dynamicCreate(compId, "group", {
		tagname : "li"
	}, $p.getComponentById(pagination.id));
	liComp = $p.getComponentById(compId);
	liComp.addClass("pagination-btn-item");
	liComp.setTitle("다음");
	document.getElementById(liComp.getID()).innerHTML = ">>";
	*/

	var paginationItems = scwin.initData[compOrgId].chartWrap.querySelectorAll(".slider-pagination > .pagination-item");
	var paginationBtnItems = scwin.initData[compOrgId].chartWrap.querySelectorAll(".slider-pagination > .pagination-btn-item");

	/* 
	// 첫 화면 로딩시 두번째 차트가 불러와져서 주석 처리함_240126
	var offset = scwin.initData[compOrgId].sliderWidth + scwin.initData[compOrgId].currSlide;
	sliderItems.forEach(emt => {
		emt.setAttribute("style", `left: ${-offset}px`);
	});
	*/

	// 각 페이지네이션 클릭 시 해당 슬라이드로 이동하기
	for (var i = 0; i < slideCount; i++) {
		// 각 페이지네이션마다 클릭 이벤트 추가하기
		paginationItems[i].addEventListener("click", e => {
			// 클릭한 페이지네이션에 따라 현재 슬라이드 변경해주기(currSlide는 시작 위치가 1이기 때문에 + 1)
			var i = [...paginationItems].findIndex(emt => emt == e.target);
			scwin.initData[compOrgId].currSlide = i;
			// 슬라이드를 이동시키기 위한 offset 계산
			//var offset = scwin.initData[compOrgId].sliderWidth * scwin.initData[compOrgId].currSlide;
			var offset = 100 * i;
			sliderItems.forEach(emt => {
				//emt.setAttribute("style", `transition: 0.2s; left: ${-offset}px`);
				emt.setAttribute("style", `left: ${-offset}%`);
			});
			// 슬라이드 이동 시 현재 활성화된 pagination 변경
			paginationItems.forEach(emt => emt.classList.remove("active"));
			paginationItems[scwin.initData[compOrgId].currSlide].classList.add("active");
		});
	}
	// 이전 버튼 클릭 시 해당 슬라이드로 이동하기
	paginationBtnItems[0].addEventListener("click", e => {
		var targetEmt = e.target;
		while(!targetEmt.classList.contains("chart-wrap")) {
			targetEmt = targetEmt.parentElement;
			if (targetEmt.classList.contains("main-chart-pcc") || targetEmt.tagName.toLowerCase() == "body") {
				break;
			}
		}
		var targetEmtOriginalID = targetEmt.id.substr(targetEmt.id.lastIndexOf("_") + "_".length);
		scwin.prevMove(targetEmtOriginalID);
	});
	// 다음 버튼 클릭 시 해당 슬라이드로 이동하기
	paginationBtnItems[1].addEventListener("click", e => {
		var targetEmt = e.target;
		while(!targetEmt.classList.contains("chart-wrap")) {
			targetEmt = targetEmt.parentElement;
			if (targetEmt.classList.contains("main-chart-pcc") || targetEmt.tagName.toLowerCase() == "body") {
				break;
			}
		}
		var targetEmtOriginalID = targetEmt.id.substr(targetEmt.id.lastIndexOf("_") + "_".length);
		scwin.nextMove(targetEmtOriginalID);
	});

	// 브라우저 화면이 조정될 때 마다 slideWidth를 변경하기 위해
	window.addEventListener("resize", e => {
		scwin.initData.grpChartElyrsErn.sliderWidth = scwin.initData.grpChartElyrsErn.chartWrap.querySelector(".slider").clientWidth;
	});

	/* 자동 슬라이드 기능 없애달래서 주석처리함_0920
	// 기본적으로 슬라이드 루프 시작하기
	scwin.initData[compOrgId].loopInterval = setInterval(() => {
		scwin.nextMove(compOrgId);
	}, scwin.initData.chart.sliderIntervalTime);
	*/

	/* 자동 슬라이드 기능 없애달래서 주석처리함_0920
	// 슬라이드에 마우스가 올라간 경우 루프 멈추기
	scwin.initData[compOrgId].chartWrap.addEventListener("mouseover", e => {
		<!--
		if (!scwin.initData.chart.dashChartEvent) {
			scwin.initData.chart.dashChartEvent = true;
			setTimeout(() => {
				scwin.initData.chart.dashChartEvent = false;
			}, 200);
		}
		!-->
		var targetEmt = e.target;
		while(!targetEmt.classList.contains("chart-wrap")) {
			targetEmt = targetEmt.parentElement;
			if (targetEmt.classList.contains("dash-box") || targetEmt.tagName.toLowerCase() == "body") {
				break;
			}
		}
		var targetEmtOriginalID = targetEmt.id.substr(targetEmt.id.lastIndexOf("_") + "_".length);
		clearInterval(scwin.initData[targetEmtOriginalID].loopInterval);
	});
	*/

	/* 자동 슬라이드 기능 없애달래서 주석처리함_0918
	// 슬라이드에서 마우스가 나온 경우 루프 재시작하기
	scwin.initData[compOrgId].chartWrap.addEventListener("mouseout", e => {
		<!--
		var targetEmt = e.target;
		while(!targetEmt.classList.contains("chart-wrap")) {
			targetEmt = targetEmt.parentElement;
			if (targetEmt.classList.contains("dash-box") || targetEmt.tagName.toLowerCase() == "body") {
				break;
			}
		}
		var targetEmtOriginalID = targetEmt.id.substr(targetEmt.id.lastIndexOf("_") + "_".length);
		clearInterval(scwin.initData[targetEmtOriginalID].loopInterval);
		scwin.initData[targetEmtOriginalID].loopInterval = setInterval(() => {
			scwin.nextMove(targetEmtOriginalID);
		}, scwin.initData.chart.sliderIntervalTime);
		--!>
		// 2023.06.15 마우스 올라가면 전체 멈춤으로 변경
		clearInterval(scwin.initData.grpChartElyrsErn.loopInterval);
		clearInterval(scwin.initData.grpChartEtcErn.loopInterval);
		clearInterval(scwin.initData.grpChartCnstnExcclc.loopInterval);
		scwin.initData.grpChartElyrsErn.loopInterval = setInterval(() => {
			scwin.nextMove("grpChartElyrsErn");
		}, scwin.initData.chart.sliderIntervalTime);
		scwin.initData.grpChartEtcErn.loopInterval = setInterval(() => {
			scwin.nextMove("grpChartEtcErn");
		}, scwin.initData.chart.sliderIntervalTime);
		scwin.initData.grpChartCnstnExcclc.loopInterval = setInterval(() => {
			scwin.nextMove("grpChartCnstnExcclc");
		}, scwin.initData.chart.sliderIntervalTime);
	});
	*/

	// 드래그(스와이프) 이벤트를 위한 변수 초기화
	scwin.initData.startPoint = 0;
	scwin.initData.endPoint = 0;

	// PC 클릭 이벤트 (드래그)
	scwin.initData[compOrgId].chartWrap.addEventListener("mousedown", e => {
		var targetEmt = e.target;
		while(!targetEmt.classList.contains("chart-wrap")) {
			targetEmt = targetEmt.parentElement;
			if (targetEmt.classList.contains("dash-box") || targetEmt.tagName.toLowerCase() == "body") {
				break;
			}
			targetEmt.style.cursor = "all-scroll";
		}
		// 마우스 드래그 시작 위치 저장
		scwin.initData.startPoint = e.pageX;
	});

	scwin.initData[compOrgId].chartWrap.addEventListener("mouseup", e => {
		var targetEmt = e.target;
		while(!targetEmt.classList.contains("chart-wrap")) {
			targetEmt = targetEmt.parentElement;
			if (targetEmt.classList.contains("dash-box") || targetEmt.tagName.toLowerCase() == "body") {
				break;
			}
			targetEmt.style.cursor = "";
		}
		var targetEmtOriginalID = targetEmt.id.substr(targetEmt.id.lastIndexOf("_") + "_".length);
		// 마우스 드래그 끝 위치 저장
		scwin.initData.endPoint = e.pageX;
		if (scwin.initData.startPoint < scwin.initData.endPoint) {
			// 마우스가 오른쪽으로 드래그 된 경우
			scwin.prevMove(targetEmtOriginalID);
		} else if (scwin.initData.startPoint > scwin.initData.endPoint) {
			// 마우스가 왼쪽으로 드래그 된 경우
			scwin.nextMove(targetEmtOriginalID);
		}
	});
};

scwin.nextMove = function(compOriginalID) {
	var sliderEmt = scwin.initData[compOriginalID].chartWrap.querySelector(".slider");
	if (!scwin.initData[compOriginalID].sliderWidth) {
		scwin.initData[compOriginalID].sliderWidth = sliderEmt.clientWidth;
	}
	var sliderItems = sliderEmt.querySelectorAll(".slider-item");
	var slideCount = sliderItems.length;
	var paginationItems = scwin.initData[compOriginalID].chartWrap.querySelectorAll(".slider-pagination > .pagination-item");

	scwin.initData[compOriginalID].currSlide++;
	// 마지막 슬라이드 이상으로 넘어가지 않게 하기 위해서
	if (scwin.initData[compOriginalID].currSlide < slideCount) {
		//var offset = scwin.initData[compOriginalID].sliderWidth * scwin.initData[compOriginalID].currSlide;
		var offset = 100 * scwin.initData[compOriginalID].currSlide;
		sliderItems.forEach(emt => {
			//emt.setAttribute("style", `left: ${-offset}px`);
			emt.setAttribute("style", `left: ${-offset}%`);
		});
		// 슬라이드 이동 시 현재 활성화된 pagination 변경
		paginationItems.forEach(emt => emt.classList.remove("active"));
		paginationItems[scwin.initData[compOriginalID].currSlide].classList.add("active");
	} else {
		// 무한 슬라이드 기능 - currSlide 값만 변경해줘도 되지만 시각적으로 자연스럽게 하기 위해 아래 코드 작성
		scwin.initData[compOriginalID].currSlide = 0;
		//var offset = scwin.initData[compOriginalID].sliderWidth * scwin.initData[compOriginalID].currSlide;
		var offset = 100 * scwin.initData[compOriginalID].currSlide;
		setTimeout(() => {
			// 각 슬라이드 아이템의 left에 offset 적용
			sliderItems.forEach(emt => {
				//emt.setAttribute("style", `transition: ${0}s; left: ${-offset}px`);
				//emt.setAttribute("style", `transition: 0.4s; left: ${-offset}px`);
				emt.setAttribute("style", `transition: 0.4s; left: ${-offset}%`);
			});
		}, 0);
		// 슬라이드 이동 시 현재 활성화된 pagination 변경
		paginationItems.forEach(emt => emt.classList.remove("active"));
		paginationItems[scwin.initData[compOriginalID].currSlide].classList.add("active");
	}
};

scwin.prevMove = function(compOriginalID) {
	var sliderEmt = scwin.initData[compOriginalID].chartWrap.querySelector(".slider");
	if (!scwin.initData[compOriginalID].sliderWidth) {
		scwin.initData[compOriginalID].sliderWidth = sliderEmt.clientWidth;
	}
	var sliderItems = sliderEmt.querySelectorAll(".slider-item");
	var slideCount = sliderItems.length;
	var paginationItems = scwin.initData[compOriginalID].chartWrap.querySelectorAll(".slider-pagination > .pagination-item");

	scwin.initData[compOriginalID].currSlide--;
	// 1번째 슬라이드 이하로 넘어가지 않게 하기 위해서
	if (scwin.initData[compOriginalID].currSlide >= 0) {
		//var offset = scwin.initData[compOriginalID].sliderWidth * scwin.initData[compOriginalID].currSlide;
		var offset = 100 * scwin.initData[compOriginalID].currSlide;
		sliderItems.forEach(emt => {
			//emt.setAttribute("style", `left: ${-offset}px`);
			emt.setAttribute("style", `left: ${-offset}%`);
		});
		// 슬라이드 이동 시 현재 활성화된 pagination 변경
		paginationItems.forEach(emt => emt.classList.remove("active"));
		paginationItems[scwin.initData[compOriginalID].currSlide].classList.add("active");
	} else {
		// 무한 슬라이드 기능 - currSlide 값만 변경해줘도 되지만 시각적으로 자연스럽게 하기 위해 아래 코드 작성
		scwin.initData[compOriginalID].currSlide = slideCount - 1;
		//var offset = scwin.initData[compOriginalID].sliderWidth * scwin.initData[compOriginalID].currSlide;
		var offset = 100 * scwin.initData[compOriginalID].currSlide;
		setTimeout(() => {
			// 각 슬라이드 아이템의 left에 offset 적용
			sliderItems.forEach(emt => {
				//emt.setAttribute("style", `transition: 0.4s; left: ${-offset}px`);
				emt.setAttribute("style", `transition: 0.4s; left: ${-offset}%`);
			});
		}, 0);
		// 슬라이드 이동 시 현재 활성화된 pagination 변경
		paginationItems.forEach(emt => emt.classList.remove("active"));
		paginationItems[scwin.initData[compOriginalID].currSlide].classList.add("active");
	}
};

/**
 * 연간 수익 서브박스를 클릭하면 차트가 변경된다._0920
 * @param
 * @return
 */
scwin.squareBoxClickEvent = function() {
	var squareBox = document.querySelectorAll("#" + $p.getFrameId() + " .dash-square");

	for (var i = 0; i < squareBox.length; i++) {
		squareBox[i].addEventListener("click", function(e) {
			var elyrsErnLabel = Object.values(scwin.initData.chart.elyrsErnLabel);
			var etcErnLabel = Object.values(scwin.initData.chart.etcErnLabel);
			var cnstnExcclcLabel = Object.values(scwin.initData.chart.cnstnExcclcLabel);
			var target = e.currentTarget.className.split("-")[3];
			var targetText = target.replace(/^[a-z]/, char => char.toUpperCase());

			// targetName 값 리세팅_240110
			if (scwin.initData.chart.elyrsErnLabel[targetText]) {
				var targetName = scwin.initData.chart.elyrsErnLabel[targetText];
			} else if (scwin.initData.chart.etcErnLabel[targetText]) {
				var targetName = scwin.initData.chart.etcErnLabel[targetText];
			} else if (scwin.initData.chart.cnstnExcclcLabel[targetText]) {
				var targetName = scwin.initData.chart.cnstnExcclcLabel[targetText];
			}

			// comp 값 세팅
			if (elyrsErnLabel.includes(targetName)) {
				var comp = grpChartElyrsErn;
			} else if (etcErnLabel.includes(targetName)) {
				var comp = grpChartEtcErn;
			} else if (cnstnExcclcLabel.includes(targetName)) {
				var comp = grpChartCnstnExcclc;
			}
			var compOrgId = comp.getOriginalID();
			scwin.initData[compOrgId].chartWrap = document.querySelector(`#${comp.getID()}`);

			// 현재 페이지의 전체 pagination-item 리스트
			var paginationList = document.querySelectorAll("#" + $p.getFrameId() + " .slider-pagination > .pagination-item");
			// 변경될 차트 그룹의 pagination-item 리스트
			var paginationItemsGrp = scwin.initData[compOrgId].chartWrap.querySelectorAll(".slider-pagination > .pagination-item");
			var i = [...squareBox].findIndex(emt => emt == e.currentTarget);

			// 해당 페이지네이션 아이템 클릭
			paginationList[i].click();
		});
	}
};
